#include <stdio.h>
#include <stdlib.h>

#define MAXK 1000000

int main(){
    static int phi[MAXK+2];
    static int ans[MAXK+1];
    int i, j;
    // linear sieve for phi up to MAXK+1
    int primes[MAXK];
    int pcnt=0;
    phi[0]=0; phi[1]=1;
    for(i=2;i<=MAXK+1;i++) phi[i]=0;
    for(i=2;i<=MAXK+1;i++){
        if(!phi[i]){ phi[i]=i-1; primes[pcnt++]=i; }
        for(j=0;j<pcnt && (long long)i*primes[j]<=MAXK+1; j++){
            int p=primes[j];
            int v=i*p;
            if(i%p==0){ phi[v]=phi[i]*p; break; }
            else phi[v]=phi[i]*(p-1);
        }
    }
    // build ans[k] = sum_{d|k} phi(d+1)
    for(i=1;i<=MAXK;i++){
        int add = phi[i+1];
        for(j=i;j<=MAXK;j+=i) ans[j] += add;
    }
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int k; scanf("%d", &k);
        long long res = 2LL * ans[k];
        printf("%lld\n", res);
    }
    return 0;
}

