import java.io.*;
import java.util.*;

public class Main {
    static final int MAXK = 1_000_000;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int[] phi = new int[MAXK + 2];
        int[] ans = new int[MAXK + 1];
        // linear sieve for phi
        List<Integer> primes = new ArrayList<>();
        phi[0] = 0; phi[1] = 1;
        for (int i = 2; i <= MAXK + 1; i++) {
            if (phi[i] == 0) {
                phi[i] = i - 1;
                primes.add(i);
            }
            for (int p : primes) {
                long v = (long) i * p;
                if (v > MAXK + 1) break;
                if (i % p == 0) {
                    phi[(int) v] = phi[i] * p;
                    break;
                } else {
                    phi[(int) v] = phi[i] * (p - 1);
                }
            }
        }
        // build ans
        for (int d = 1; d <= MAXK; d++) {
            int add = phi[d + 1];
            for (int k = d; k <= MAXK; k += d) ans[k] += add;
        }
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int k = fs.nextInt();
            long res = 2L * ans[k];
            sb.append(res).append('\n');
        }
        System.out.print(sb.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

