const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
const MAXK = 1000000;
// linear sieve for phi up to MAXK+1
const phi = new Uint32Array(MAXK + 2);
phi[1] = 1;
const primes = [];
for (let i = 2; i <= MAXK + 1; i++) {
  if (phi[i] === 0) {
    phi[i] = i - 1;
    primes.push(i);
  }
  for (let pIdx = 0; pIdx < primes.length; pIdx++) {
    const p = primes[pIdx];
    const v = i * p;
    if (v > MAXK + 1) break;
    if (i % p === 0) {
      phi[v] = phi[i] * p;
      break;
    } else {
      phi[v] = phi[i] * (p - 1);
    }
  }
}
// precompute answers
const ans = new Uint32Array(MAXK + 1);
for (let d = 1; d <= MAXK; d++) {
  const add = phi[d + 1];
  for (let k = d; k <= MAXK; k += d) ans[k] += add;
}
let out = [];
for (let t = 0; t < T; t++) {
  const k = input[idx++];
  out.push(String(2 * ans[k]));
